parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let deck;

try {
  deck = JSON.parse(cleaned);

  if (!Array.isArray(deck.slides)) {
    throw new Error("Invalid slides format");
  }
} catch (error) {
  deck = {
    title: "Demo Slide Deck",
    description: "A fallback Study Aura slide outline.",
    slides: [
      {
        slideNumber: 1,
        title: "Introduction to Marine Biology",
        subtitle: "Understanding ocean life",
        bullets: ["Marine biology studies ocean organisms", "It covers ecosystems, behavior, and conservation", "Dolphins and coral reefs are common examples"],
        speakerNotes: "Introduce marine biology as the study of life in the ocean.",
        visualIdea: "Ocean background with icons of dolphins, coral, and fish"
      }
    ]
  };
}

const slides = deck.slides.map((slide, index) => ({
  slideNumber: Number(slide.slideNumber || index + 1),
  title: String(slide.title || `Slide ${index + 1}`),
  subtitle: String(slide.subtitle || "Study Aura slide"),
  bullets: Array.isArray(slide.bullets)
    ? slide.bullets.map((bullet) => String(bullet)).slice(0, 5)
    : ["Review the key idea"],
  speakerNotes: String(slide.speakerNotes || "Explain this concept clearly."),
  visualIdea: String(slide.visualIdea || "Use a simple educational visual.")
}));

return [
  {
    json: {
      deck: {
        title: String(deck.title || "Study Aura Slide Deck"),
        description: String(deck.description || "Generated slide outline."),
        slides
      },
      fallback: false
    }
  }
];

